#!/usr/bin/env python3
import os
import re

def check_files():
    issues = []

    # Count occurrences of new name
    for root, dirs, files in os.walk('/workspace/numpy'):
        # Skip test and cache directories for now
        if '__pycache__' in root or '.git' in root:
            continue

        for file in files:
            if not file.endswith('.py'):
                continue

            filepath = os.path.join(root, file)
            with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
                content = f.read()
                lines = content.split('\n')

            for i, line in enumerate(lines, 1):
                # Check for the OLD pattern that shouldn't exist anymore
                # But allow it in comments/docstrings describing the OLD name
                if 'array_function_dispatch' in line and 'dispatch_array_function' not in line:
                    # Skip if it's just a docstring reference
                    if '"""' not in line and "'''" not in line and 'array_function_dispatcher' not in line:
                        # This might be a real issue
                        if not any(x in line for x in ['#', 'docstring', 'Like array_function_dispatcher']):
                            issues.append(f"{filepath}:{i}: {line.strip()}")

                # Check for proper usage of new name
                if 'dispatch_array_function' in line:
                    # Should be used as function call, import, or decorator
                    if not any(x in line for x in ['def dispatch_array_function', 'dispatch_array_function(', 'import dispatch_array_function', '@dispatch_array_function', '= dispatch_array_function']):
                        # This might be an issue
                        pass

    return issues

issues = check_files()
if issues:
    print("Potential issues found:")
    for issue in issues[:20]:
        print(f"  {issue}")
    if len(issues) > 20:
        print(f"  ... and {len(issues)-20} more")
else:
    print("No issues found - all occurrences look correct!")
